var e=[{id:`L2_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_MEDIUS`,text:{KOREA:`뭐야……? 넌 그 때 늙은이 총에 맞아 죽은 놈이잖아?`,JPN:`何よ……？　あの時老いぼれの銃に撃たれて死んだんじゃなかったの？`,ENG:`What the...? Didn't you die to the old man?`,TWN:`搞什麼…？你不是已經被老頭子開槍打死嗎？`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_MEDIUS`,face:`UNIT_SURPRISE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_MEDIUS`,text:{KOREA:`설마 안 본 사이에 기똥찬 우연으로 워치라도 얻은 거야?`,JPN:`まさか見ない間にものすごい偶然でウォッチでも手に入れたわけ？`,ENG:`What is it? Did you miraculously obtain a Watch during the time?`,TWN:`難道你在這段時間，這麼剛好得到能量環嗎？`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_MEDIUS`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`그럴지도 모르지. 아닐지도 모르고.`,JPN:`そうかもしれない。そうではないかもしれないし。`,ENG:`Maybe. Maybe not.`,TWN:`也許是，也許不是。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_MEDIUS`,text:{KOREA:`후훗, 그래?`,JPN:`ふふっ、そう？`,ENG:`Fu fu, oh yeah?`,TWN:`呵呵，是嗎？`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_MEDIUS`,face:`UNIT_LAUGH`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_MEDIUS`,text:{KOREA:`상관없어. 카운터 하나 늘었다고 바뀌는 건 없으니까.`,JPN:`どうでもいいわ。カウンターが一人増えただけじゃ何も変わらないからね。`,ENG:`No matter. Having another Counter isn't going to change anything.`,TWN:`無所謂，因為多一個制裁者也不會改變任何事。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_MEDIUS`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_MEDIUS`,text:{KOREA:`너희는 어차피 여기서 전부 죽을 거야.`,JPN:`どうせあんたたちはここで全部死ぬの。`,ENG:`This place will be your grave.`,TWN:`你們反正都會死在這裡。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_MEDIUS`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`VIVIEN_OPR_NULL_NULL`,text:{KOREA:`침식체? 아직도 저렇게 많은 녀석들을 불러들일 힘이 남아 있는 건가?`,JPN:`侵食体？　まだあんなに大量の侵食体を呼び寄せる力が残ってるのか？`,ENG:`C.O.s? She still has the strength to summon that many?`,TWN:`侵蝕體？她還有餘力召喚那麼侵蝕體嗎？`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`지휘관, 어떻게 할 거야?`,JPN:`指揮官、どうする？`,ENG:`Commander, what do we do?`,TWN:`指揮官，你打算怎麼辦？`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`내가 그림자를 맡지. 주변의 침식체들을 부탁한다, 대장.`,JPN:`私がシャドウを受け持つ。周りの侵食体を頼むぞ、隊長。`,ENG:`I'll take on the Shadow. You take the C.O.s, Captain.`,TWN:`我負責暗影，周圍的侵蝕體就麻煩你了，隊長。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`혼자 맡겠다고? 할 수 있겠어?`,JPN:`一人で？　できるの？`,ENG:`You're going in alone? Are you sure about that?`,TWN:`你一個人嗎？可以嗎？`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`혼자는 아니지. 내 오랜 벗이 함께 있으니.`,JPN:`一人ではない。私の旧友が共にいるからな。`,ENG:`I'm not alone. I have my old friend with me.`,TWN:`不是我一個人，還有我的老朋友。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`……그래.`,JPN:`……そう。`,ENG:`...Okay.`,TWN:`……原來如此。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`전 대원. 침식체들이 능선을 넘어오지 못하게 막아라.`,JPN:`総員。侵食体が尾根を越えられないように止めろ。`,ENG:`All hands! Don't let the C.O.s cross that horizon!`,TWN:`全員注意，別讓侵蝕物越過山峰。`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`지휘관 앞을 방해하는 것들은 전부 치워버려!`,JPN:`指揮官の前を邪魔するものは全部消せ！`,ENG:`Remove anything that stands in Commander's way!`,TWN:`替指揮官除掉絆腳石！`},stage:{bg:`NOMAD_BORDER`,bgm:`THEMA_CURIAN`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`}];export{e as default};